import type { SkeletonProps as _SkeletonProps } from '@soybeanjs/headless/skeleton';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { SkeletonShape } from '@/styles/skeleton';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Skeleton component.
 */
export interface SkeletonProps extends _SkeletonProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Whether the skeleton should have an animation effect. Defaults to `true`.
   */
  animated?: boolean;
  /**
   * Shape of the component.
   */
  shape?: SkeletonShape;
}

export type { SkeletonShape };

// @unocss-include
import { cv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const skeletonVariants = cv({
  base: 'block shrink-0 bg-muted',
  variants: {
    size: {
      xs: 'h-3 w-16',
      sm: 'h-4 w-24',
      md: 'h-5 w-32',
      lg: 'h-6 w-40',
      xl: 'h-8 w-48',
      '2xl': 'h-10 w-56'
    },
    shape: {
      auto: 'rounded-md',
      rounded: 'rounded-full'
    },
    animated: {
      true: 'animate-pulse',
      false: ''
    }
  },
  defaultVariants: {
    size: 'md',
    shape: 'auto',
    animated: true
  }
});

type SkeletonVariants = VariantProps<typeof skeletonVariants>;

export type SkeletonShape = NonNullable<SkeletonVariants['shape']>;
